#include <bits/stdc++.h>
using namespace std;
struct tree{
    int left,right;
}g[100005];
int n,q,sum[100005],c[100005];
void dfs(int x){
	if(sum[x]){
		sum[x]--;
		return;
	}
	c[x]=(c[x]+1)%2;
	if(g[x].left)dfs(g[x].left);
	if(g[x].right)dfs(g[x].right);
}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)g[i].left=g[i].right=0;
    for(int i=2;i<=n;i++){
        int x;
        cin>>x;
        if(!g[x].left)g[x].left=i;
        else g[x].right=i;
    }
    string s;
    cin>>s;
    for(int i=0;i<n;i++)c[i+1]=s[i]-'0';
    cin>>q;
    while(q--){
        int x;
        cin>>x;
        sum[x]=(sum[x]+1)%2;
    }
    for(int i=1;i<=n;i++)
        if(sum[i]){
        	sum[i]--;
        	dfs(i);
		}
    for(int i=1;i<=n;i++)cout<<c[i];
    return 0;
}
